import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenerativeAI } from "@google/generative-ai";
import { collegeData } from '../data/collegeData'; 
import { Bot, Send, X, Sparkles, Loader2 } from 'lucide-react';

// 🔑 SETUP: Use the Environment Variable. 
// If it fails locally, you can temporarily paste the "AIza..." string inside the quotes below.
const API_KEY = process.env.REACT_APP_GEMINI_API_KEY || "PASTE_YOUR_API_KEY_HERE_IF_ENV_FAILS"; 

function ChatBot({ isOpen, onClose, onOpen }) {
  // --- STATE VARIABLES (These were missing in your error) ---
  const [messages, setMessages] = useState([
    { text: "Hi! I'm CampusBot. I can help you with CampusCanvas, tell you about NIMIT, or even help you write code! Ask me anything.", isBot: true }
  ]);
  const [input, setInput] = useState("");
  const [isThinking, setIsThinking] = useState(false);
  const messagesEndRef = useRef(null);

  // Auto-scroll chat
  useEffect(() => {
    if (isOpen) {
       messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }
  }, [messages, isThinking, isOpen]);

  // --- THE BRAIN (Logic) ---
  const handleSend = async () => {
    if (!input.trim()) return;

    // 1. Add User Message
    const userMsg = { text: input, isBot: false };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setIsThinking(true);

    try {
      // Check if Key exists
      if (!API_KEY || API_KEY.startsWith("PASTE")) {
         throw new Error("Missing API Key. Check ChatBot.js line 7.");
      }

      console.log("Using Key:", API_KEY); // Debugging

      const genAI = new GoogleGenerativeAI(API_KEY);
      const model = genAI.getGenerativeModel({ model: "gemini-1.5-flash" });

      // 2. The Hybrid Prompt
      const systemContext = `
        You are "CampusBot", the AI assistant for ${collegeData?.collegeInfo?.name || "NIMIT"}.
        
        DATA:
        - Depts: ${collegeData?.collegeInfo?.departments?.join(", ")}
        - Events: ${collegeData?.collegeInfo?.campusLife?.majorEvents?.join(", ")}
        - App Guide: ${collegeData?.appManual?.userGuide?.howToAddProject}
        
        INSTRUCTIONS:
        1. If asked about College/NIMIT, use the data above. If answer is missing, use your own knowledge.
        2. If asked about Code/Math/General, answer as a helpful expert AI.
      `;

      const result = await model.generateContent(`${systemContext}\n\nUser Question: ${userMsg.text}\nAnswer:`);
      const response = await result.response;
      const text = response.text();

      // 3. Add AI Response
      setIsThinking(false);
      setMessages((prev) => [...prev, { text: text, isBot: true }]);
      
    } catch (error) {
      console.error("AI Error:", error);
      setIsThinking(false);
      setMessages((prev) => [...prev, { text: `Error: ${error.message}. Check console for details.`, isBot: true }]);
    }
  };

  // --- THE UI (Visuals) ---
  return (
    <div className="fixed bottom-6 right-6 z-50 font-sans">
      
      {!isOpen && (
        <button 
          onClick={onOpen}
          className="relative group flex items-center justify-center w-14 h-14 bg-gradient-to-tr from-indigo-600 to-purple-600 rounded-full shadow-[0_0_30px_rgba(99,102,241,0.5)] hover:scale-110 transition-all duration-300 border border-white/20 animate-bounce"
        >
          <Bot className="w-6 h-6 text-white" />
          <span className="absolute top-0 right-0 w-3.5 h-3.5 bg-green-500 border-2 border-[#0a0a0a] rounded-full animate-pulse"></span>
        </button>
      )}

      {isOpen && (
        <div className="w-[380px] h-[600px] max-h-[80vh] bg-[#0a0a0a]/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-[0_0_50px_rgba(0,0,0,0.8)] flex flex-col overflow-hidden animate-fade-in-up">
          
          <div className="bg-white/5 border-b border-white/10 p-4 flex items-center justify-between relative overflow-hidden shrink-0">
            <div className="flex items-center gap-3 relative z-10">
              <div className="w-10 h-10 bg-gradient-to-tr from-indigo-500 to-purple-500 rounded-xl flex items-center justify-center shadow-lg border border-white/10">
                <Bot className="w-6 h-6 text-white" />
              </div>
              <div>
                <h3 className="text-white font-bold tracking-wide flex items-center gap-1.5">
                  CampusBot <Sparkles className="w-3.5 h-3.5 text-yellow-400" />
                </h3>
                <p className="text-[10px] text-indigo-300 font-medium uppercase tracking-widest">NIMIT AI Assistant</p>
              </div>
            </div>
            <button onClick={onClose} className="relative z-10 p-2 bg-white/5 hover:bg-white/10 text-gray-400 hover:text-white rounded-full transition-colors">
              <X className="w-5 h-5" />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-hide">
            {messages.map((msg, index) => (
              <div key={index} className={`flex ${msg.isBot ? 'justify-start' : 'justify-end'}`}>
                {msg.isBot && (
                  <div className="w-8 h-8 rounded-full bg-white/10 border border-white/5 flex items-center justify-center shrink-0 mr-2 mt-1">
                    <Bot className="w-4 h-4 text-indigo-400" />
                  </div>
                )}
                <div className={`max-w-[80%] p-3.5 text-sm leading-relaxed shadow-lg ${!msg.isBot ? 'bg-indigo-600 text-white rounded-2xl rounded-tr-sm' : 'bg-white/10 text-gray-200 border border-white/5 rounded-2xl rounded-tl-sm'}`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {isThinking && (
              <div className="flex justify-start">
                 <div className="w-8 h-8 rounded-full bg-white/10 border border-white/5 flex items-center justify-center shrink-0 mr-2 mt-1">
                    <Bot className="w-4 h-4 text-indigo-400" />
                 </div>
                 <div className="bg-white/10 border border-white/5 rounded-2xl p-4 w-16 flex items-center gap-1">
                    <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></div>
                    <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-100"></div>
                    <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-200"></div>
                 </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          <div className="p-4 bg-black/40 border-t border-white/10 shrink-0">
            <div className="relative flex items-center">
              <input 
                type="text" 
                value={input} 
                onChange={(e) => setInput(e.target.value)} 
                onKeyPress={(e) => e.key === 'Enter' && handleSend()}
                placeholder="Ask anything..." 
                className="w-full bg-white/5 border border-white/10 rounded-xl pl-4 pr-12 py-3.5 text-sm text-white outline-none focus:border-indigo-500 focus:bg-white/10 transition-all placeholder-gray-500"
              />
              <button onClick={handleSend} disabled={isThinking || !input.trim()} className={`absolute right-2 p-2 rounded-lg transition-colors ${isThinking || !input.trim() ? 'bg-gray-700 text-gray-500 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-lg'}`}>
                {isThinking ? <Loader2 className="w-4 h-4 animate-spin"/> : <Send className="w-4 h-4" />}
              </button>
            </div>
          </div>

        </div>
      )}
    </div>
  );
}

export default ChatBot;
